2007	/**
2008	 * @typedef {Object} ImageClassificationSingle
2009	 * @property {string} label The label identified by the model.
2010	 * @property {number} score The score attributed by the model for that label.
2011	 * @typedef {ImageClassificationSingle[]} ImageClassificationOutput
2012	 *
2013	 * @typedef {Object} ImageClassificationPipelineOptions Parameters specific to image classification pipelines.
2014	 * @property {number} [top_k=1] The number of top labels that will be returned by the pipeline.
2015	 *
2016	 * @callback ImageClassificationPipelineCallback Assign labels to the image(s) passed as inputs.
2017	 * @param {ImagePipelineInputs} images The input images(s) to be classified.
2018	 * @param {ImageClassificationPipelineOptions} [options] The options to use for image classification.
2019	 * @returns {Promise<ImageClassificationOutput|ImageClassificationOutput[]>} An array or object containing the predicted labels and scores.
2020	 *
2021	 * @typedef {ImagePipelineConstructorArgs & ImageClassificationPipelineCallback & Disposable} ImageClassificationPipelineType
2022	 */
2023	
2024	/**
2025	 * Image classification pipeline using any `AutoModelForImageClassification`.
2026	 * This pipeline predicts the class of an image.
2027	 *
2028	 * **Example:** Classify an image.
2029	 * ```javascript
2030	 * const classifier = await pipeline('image-classification', 'Xenova/vit-base-patch16-224');
2031	 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/tiger.jpg';
2032	 * const output = await classifier(url);
2033	 * // [
2034	 * //   { label: 'tiger, Panthera tigris', score: 0.632695734500885 },
2035	 * // ]
2036	 * ```
2037	 *
2038	 * **Example:** Classify an image and return top `n` classes.
2039	 * ```javascript
2040	 * const classifier = await pipeline('image-classification', 'Xenova/vit-base-patch16-224');
2041	 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/tiger.jpg';
2042	 * const output = await classifier(url, { top_k: 3 });
2043	 * // [
2044	 * //   { label: 'tiger, Panthera tigris', score: 0.632695734500885 },
2045	 * //   { label: 'tiger cat', score: 0.3634825646877289 },
2046	 * //   { label: 'lion, king of beasts, Panthera leo', score: 0.00045060308184474707 },
2047	 * // ]
2048	 * ```
2049	 *
2050	 * **Example:** Classify an image and return all classes.
2051	 * ```javascript
2052	 * const classifier = await pipeline('image-classification', 'Xenova/vit-base-patch16-224');
2053	 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/tiger.jpg';
2054	 * const output = await classifier(url, { top_k: 0 });
2055	 * // [
2056	 * //   { label: 'tiger, Panthera tigris', score: 0.632695734500885 },
2057	 * //   { label: 'tiger cat', score: 0.3634825646877289 },
2058	 * //   { label: 'lion, king of beasts, Panthera leo', score: 0.00045060308184474707 },
2059	 * //   { label: 'jaguar, panther, Panthera onca, Felis onca', score: 0.00035465499968267977 },
2060	 * //   ...
2061	 * // ]
2062	 * ```
2063	 */
2064	export class ImageClassificationPipeline extends (/** @type {new (options: ImagePipelineConstructorArgs) => ImageClassificationPipelineType} */ (Pipeline)) {
2065	
2066	    /**
2067	     * Create a new ImageClassificationPipeline.
2068	     * @param {ImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
2069	     */
2070	    constructor(options) {
2071	        super(options);
2072	    }
2073	
2074	    /** @type {ImageClassificationPipelineCallback} */
2075	    async _call(images, {
2076	        top_k = 5
2077	    } = {}) {
2078	
2079	        const preparedImages = await prepareImages(images);
2080	
2081	        const { pixel_values } = await this.processor(preparedImages);
2082	        const output = await this.model({ pixel_values });
2083	
2084	        // @ts-expect-error TS2339
2085	        const id2label = this.model.config.id2label;
2086	
2087	        /** @type {ImageClassificationOutput[]} */
2088	        const toReturn = [];
2089	        for (const batch of output.logits) {
2090	            const scores = await topk(new Tensor(
2091	                'float32',
2092	                softmax(batch.data),
2093	                batch.dims,
2094	            ), top_k);
2095	
2096	            const values = scores[0].tolist();
2097	            const indices = scores[1].tolist();
2098	
2099	            const vals = indices.map((x, i) => ({
2100	                label: /** @type {string} */ (id2label ? id2label[x] : `LABEL_${x}`),
2101	                score: /** @type {number} */ (values[i]),
2102	            }));
2103	            toReturn.push(vals);
2104	        }
2105	
2106	        return Array.isArray(images) ? toReturn : toReturn[0];
2107	    }
2108	
2109	}
