/**
 * @typedef {Object} ImageTextToTextSingle
 * @property {string} generated_text The generated text.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Generate text given an image and a text prompt using a vision-language model.
 * @param {ImagePipelineInputs} images The image(s) to use as input.
 * @param {string|string[]} [text] The text prompt(s) to use as input.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput|ImageTextToTextOutput[]>} An object (or array of objects) containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-Text-to-Text pipeline using an `AutoModelForImageTextToText`. This pipeline generates
 * text given an image and an optional text prompt, enabling tasks like visual question answering,
 * image-based chat, and image captioning with instruction.
 *
 * **Example:** Generate a description of an image with a text prompt.
 * ```javascript
 * const generator = await pipeline('image-text-to-text', 'Xenova/llava-1.5-7b-hf');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await generator(url, 'Describe this image.');
 * // [{ generated_text: '...' }]
 * ```
 *
 * **Example:** Generate text from multiple images with different prompts.
 * ```javascript
 * const generator = await pipeline('image-text-to-text', 'Xenova/llava-1.5-7b-hf');
 * const urls = [
 *   'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg',
 *   'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/tiger.jpg',
 * ];
 * const output = await generator(urls, ['Describe this image.', 'What animal is this?']);
 * // [[{ generated_text: '...' }], [{ generated_text: '...' }]]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, text = null, generate_kwargs = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        const toReturn = [];
        for (let i = 0; i < preparedImages.length; ++i) {
            const image = preparedImages[i];

            // Get text prompt for this image
            const prompt = Array.isArray(text) ? text[i] : text;

            // Process image
            const imageProcessed = await this.processor(image);

            // Tokenize text if provided
            const textInputs = prompt != null
                ? this.tokenizer(prompt, {
                    padding: true,
                    truncation: true,
                })
                : {};

            // Run model
            const output = await this.model.generate({
                ...imageProcessed,
                ...textInputs,
                ...generate_kwargs,
            });

            const decoded = this.tokenizer.batch_decode(/** @type {Tensor} */(output), {
                skip_special_tokens: true,
